count = 0
for filename, content in schemes:
    filepath = f"data/{filename}.txt"
    if not os.path.exists(filepath):
        with open(filepath, "w", encoding="utf-8") as f:
            f.write(content)
        print(f"Created: {filepath}")
        count += 1
    else:
        print(f"Exists: {filepath}")

total = len(os.listdir("data"))
print(f"\nNew files created: {count}")
print(f"Total files in data/: {total}")